    30	    }
    31	    let (refname, head_oid) = refs.into_iter().next().expect("length checked");
    32	    let Some(default_branch) = refname.strip_prefix("refs/heads/") else {
    33	        return Err(ApiError::bad_request("only branch pushes are supported"));
    34	    };
    35	    ensure_default_branch(default_branch)?;
    36	    let tree_oid = git_stdout_text(
