   135	                );
   136	                return Err(error);
   137	            }
   138	        };
   139	    for ((path, live_content), new_content) in changed_paths.into_iter().zip(changed_blobs) {
   140	        if !source_content_matches(live_content.as_ref(), Some(&new_content)) {
   141	            changes.push(ReceivePackFileChange {
   142	                path,
